function calculateROI(inputs) {
    const initial_cost = parseFloat(inputs.initial_cost);
    const annual_energy_savings_percentage = parseFloat(inputs.annual_energy_savings_percentage) / 100;
    const current_annual_energy_bill = parseFloat(inputs.current_annual_energy_bill);
    const inflation_rate = parseFloat(inputs.inflation_rate) / 100;
    const incentives = parseFloat(inputs.incentives);
    const maintenance_cost_increase = parseFloat(inputs.maintenance_cost_increase);
    const discount_rate = parseFloat(inputs.discount_rate) / 100;

    // Input validation
    if (isNaN(initial_cost) || initial_cost < 0 ||
        isNaN(annual_energy_savings_percentage) || annual_energy_savings_percentage < 0 || annual_energy_savings_percentage > 1 ||
        isNaN(current_annual_energy_bill) || current_annual_energy_bill < 0 ||
        isNaN(inflation_rate) ||
        isNaN(incentives) || incentives < 0 ||
        isNaN(maintenance_cost_increase) ||
        isNaN(discount_rate) || discount_rate < 0) {
        return {
            error: "Please ensure all inputs are valid non-negative numbers. Energy savings percentage must be between 0 and 100, and discount rate cannot be negative."
        };
    }

    const calculation_horizon_years = 50; // Max years to iterate for discounted payback, capped for practicality
    const roi_npv_period_years = 20; // Fixed period for ROI and NPV outputs, standard for many investments

    // 1. Net Investment
    const net_investment = initial_cost - incentives;

    // Calculate annual savings for year 1
    const annual_energy_savings_amount_year1 = current_annual_energy_bill * annual_energy_savings_percentage;

    // Annual Cash Flow Year 1 (Savings - Increased Maintenance)
    const annual_cash_flow_year1 = annual_energy_savings_amount_year1 - maintenance_cost_increase;

    // Edge case: Investment made, but no positive cash flow to cover it over time
    if (net_investment > 0 && annual_cash_flow_year1 <= 0) {
        return {
            net_investment: parseFloat(net_investment.toFixed(2)),
            annual_cash_flow_year1: parseFloat(annual_cash_flow_year1.toFixed(2)),
            payback_period_years: Infinity,
            discounted_payback_period_years: Infinity,
            npv_20_years: parseFloat((-net_investment).toFixed(2)), // Initial loss is the only outcome
            roi_20_years_percentage: parseFloat((-100).toFixed(2)) // 100% loss
        };
    }

    // Edge case: Net investment is zero or negative (incentives cover everything or more)
    if (net_investment <= 0) {
        let cumulative_discounted_cash_flow_over_roi_npv_period = 0;
        for (let year = 1; year <= roi_npv_period_years; year++) {
            const energy_bill_this_year = current_annual_energy_bill * Math.pow(1 + inflation_rate, year - 1);
            const savings_this_year = energy_bill_this_year * annual_energy_savings_percentage;
            const cash_flow_this_year = savings_this_year - maintenance_cost_increase;
            const discounted_cash_flow_this_year = cash_flow_this_year / Math.pow(1 + discount_rate, year);
            cumulative_discounted_cash_flow_over_roi_npv_period += discounted_cash_flow_this_year;
        }

        // NPV in this scenario is the initial 'gain' from negative net investment plus future discounted cash flows
        const npv_when_net_investment_is_negative = -net_investment + cumulative_discounted_cash_flow_over_roi_npv_period;

        return {
            net_investment: parseFloat(net_investment.toFixed(2)),
            annual_cash_flow_year1: parseFloat(annual_cash_flow_year1.toFixed(2)),
            payback_period_years: 0, // Instant payback
            discounted_payback_period_years: 0, // Instant payback
            npv_20_years: parseFloat(npv_when_net_investment_is_negative.toFixed(2)),
            roi_20_years_percentage: Infinity // Infinite return as no out-of-pocket investment
        };
    }

    // --- Normal Calculation Path (net_investment > 0 and annual_cash_flow_year1 > 0) ---

    // Simple Payback Period
    const payback_period_years = net_investment / annual_cash_flow_year1;

    let cumulative_discounted_cash_flow = 0;
    let discounted_payback_period_years = Infinity;
    let npv_20_years = -net_investment; // Start NPV calculation with the initial cash outflow
    let total_discounted_cash_flow_for_roi = 0; // Accumulator for ROI calculation

    for (let year = 1; year <= calculation_horizon_years; year++) {
        // Calculate energy bill and savings for the current year, considering inflation
        const energy_bill_this_year = current_annual_energy_bill * Math.pow(1 + inflation_rate, year - 1);
        const savings_this_year = energy_bill_this_year * annual_energy_savings_percentage;

        // Calculate the net cash flow for the current year
        const cash_flow_this_year = savings_this_year - maintenance_cost_increase;

        // Calculate the discounted cash flow for the current year
        const discounted_cash_flow_this_year = cash_flow_this_year / Math.pow(1 + discount_rate, year);

        // Update Discounted Payback Period if not already reached
        if (discounted_payback_period_years === Infinity) {
            cumulative_discounted_cash_flow += discounted_cash_flow_this_year;
            if (cumulative_discounted_cash_flow >= net_investment) {
                // Interpolate for a more precise payback year
                discounted_payback_period_years = year - 1 + (net_investment - (cumulative_discounted_cash_flow - discounted_cash_flow_this_year)) / discounted_cash_flow_this_year;
            }
        }

        // Update NPV and ROI calculations, but only up to the defined roi_npv_period_years
        if (year <= roi_npv_period_years) {
            npv_20_years += discounted_cash_flow_this_year;
            total_discounted_cash_flow_for_roi += discounted_cash_flow_this_year;
        }
    }

    // Calculate ROI over the 20-year period
    // ROI = (Total Discounted Benefits - Net Investment) / Net Investment * 100
    let roi_20_years_percentage = ((total_discounted_cash_flow_for_roi - net_investment) / net_investment) * 100;

    return {
        net_investment: parseFloat(net_investment.toFixed(2)),
        annual_cash_flow_year1: parseFloat(annual_cash_flow_year1.toFixed(2)),
        payback_period_years: parseFloat(payback_period_years.toFixed(1)),
        discounted_payback_period_years: parseFloat(discounted_payback_period_years.toFixed(1)),
        npv_20_years: parseFloat(npv_20_years.toFixed(2)),
        roi_20_years_percentage: parseFloat(roi_20_years_percentage.toFixed(2))
    };
}
